// ---------- week calendar ----------
function WeekCalendar({ econ, earnings, onRetryEcon, onRetryEarnings }) {
  const week = tradingWeek();
  const econEvents = (econ.data && econ.data.events) || [];
  const earnRows = (earnings.data && earnings.data.earnings) || [];
  const nothingYet = econ.status === "idle" && earnings.status === "idle";

  return (
    <div
      style={{
        background: T.panel,
        border: `1px solid ${T.panelEdge}`,
        borderRadius: 10,
        overflow: "hidden",
      }}
    >
      <div
        style={{
          display: "flex",
          flexWrap: "wrap",
          alignItems: "center",
          justifyContent: "space-between",
          gap: 10,
          padding: "10px 14px",
          borderBottom: `1px solid ${T.panelEdge}`,
        }}
      >
        <div style={{ display: "flex", alignItems: "baseline", gap: 8 }}>
          <span
            style={{
              fontFamily: T.mono,
              fontSize: 11,
              letterSpacing: "0.12em",
              color: T.amber,
            }}
          >
            01
          </span>
          <span style={{ fontSize: 14, fontWeight: 600, color: T.ink }}>
            The week — {weekRangeText()}
          </span>
        </div>
        <div style={{ display: "flex", gap: 14 }}>
          <SourceStatus
            label="ECON"
            status={econ.status}
            error={econ.error}
            onRetry={onRetryEcon}
          />
          <SourceStatus
            label="EARNINGS"
            status={earnings.status}
            error={earnings.error}
            onRetry={onRetryEarnings}
          />
        </div>
      </div>

      {nothingYet ? (
        <div
          style={{
            padding: 14,
            color: T.faint,
            fontFamily: T.mono,
            fontSize: 12,
          }}
        >
          Awaiting run
        </div>
      ) : (
        <div style={{ overflowX: "auto" }}>
          <div
            style={{
              display: "grid",
              gridTemplateColumns: "repeat(5, minmax(170px, 1fr))",
              minWidth: 860,
            }}
          >
            {week.map((day, i) => {
              const today = isToday(day.date);
              const dayEcon = econEvents.filter((e) => e.day === day.label);
              const dayEarn = earnRows.filter((e) => e.day === day.label);
              return (
                <div
                  key={day.label}
                  style={{
                    borderLeft: i === 0 ? "none" : `1px solid ${T.panelEdge}`,
                    background: today ? "rgba(224,123,42,0.06)" : "transparent",
                    display: "flex",
                    flexDirection: "column",
                    minHeight: 200,
                  }}
                >
                  <div
                    style={{
                      padding: "8px 10px",
                      borderBottom: `1px solid ${T.panelEdge}`,
                      display: "flex",
                      alignItems: "baseline",
                      gap: 6,
                      borderTop: today
                        ? `2px solid ${T.amber}`
                        : "2px solid transparent",
                    }}
                  >
                    <span
                      style={{
                        fontFamily: T.mono,
                        fontSize: 11,
                        letterSpacing: "0.1em",
                        color: today ? T.amber : T.dim,
                        fontWeight: today ? 700 : 400,
                      }}
                    >
                      {day.label.toUpperCase()}
                    </span>
                    <span
                      style={{
                        fontFamily: T.mono,
                        fontSize: 11,
                        color: today ? T.ink : T.faint,
                      }}
                    >
                      {day.date.getDate()}
                    </span>
                    {today && (
                      <span
                        style={{
                          marginLeft: "auto",
                          fontFamily: T.mono,
                          fontSize: 9,
                          letterSpacing: "0.14em",
                          color: T.amber,
                        }}
                      >
                        TODAY
                      </span>
                    )}
                  </div>

                  <div style={{ padding: "8px 10px", flex: 1 }}>
                    {econ.status === "loading" && (
                      <div
                        style={{
                          fontFamily: T.mono,
                          fontSize: 10,
                          color: T.faint,
                        }}
                      >
                        loading…
                      </div>
                    )}
                    {econ.status === "done" && dayEcon.length === 0 && (
                      <div
                        style={{
                          fontFamily: T.mono,
                          fontSize: 10,
                          color: T.faint,
                        }}
                      >
                        no events
                      </div>
                    )}
                    <div
                      style={{
                        display: "flex",
                        flexDirection: "column",
                        gap: 7,
                      }}
                    >
                      {dayEcon.map((e, j) => (
                        <div key={j} style={{ display: "flex", gap: 7 }}>
                          <ImpactDot impact={e.impact} />
                          <div style={{ minWidth: 0 }}>
                            <div
                              style={{
                                fontFamily: T.mono,
                                fontSize: 10,
                                color: T.amber,
                              }}
                            >
                              {e.time_et}
                            </div>
                            <div
                              style={{
                                fontSize: 12,
                                color: T.ink,
                                lineHeight: 1.3,
                              }}
                            >
                              {e.event}
                            </div>
                            {(e.forecast || e.previous) && (
                              <div
                                style={{
                                  fontFamily: T.mono,
                                  fontSize: 10,
                                  color: T.faint,
                                }}
                              >
                                {e.forecast && `f ${e.forecast}`}
                                {e.forecast && e.previous && " · "}
                                {e.previous && `p ${e.previous}`}
                              </div>
                            )}
                          </div>
                        </div>
                      ))}
                    </div>

                    {(dayEarn.length > 0 || earnings.status === "loading") && (
                      <div
                        style={{
                          marginTop: 10,
                          paddingTop: 8,
                          borderTop: `1px dashed ${T.panelEdge}`,
                        }}
                      >
                        <div
                          style={{
                            fontFamily: T.mono,
                            fontSize: 9,
                            letterSpacing: "0.14em",
                            color: T.blue,
                            marginBottom: 6,
                          }}
                        >
                          EARNINGS
                        </div>
                        {earnings.status === "loading" && (
                          <div
                            style={{
                              fontFamily: T.mono,
                              fontSize: 10,
                              color: T.faint,
                            }}
                          >
                            loading…
                          </div>
                        )}
                        <div
                          style={{
                            display: "flex",
                            flexDirection: "column",
                            gap: 5,
                          }}
                        >
                          {dayEarn.map((e, j) => (
                            <div
                              key={j}
                              title={e.note || e.company}
                              style={{
                                display: "flex",
                                alignItems: "baseline",
                                gap: 6,
                              }}
                            >
                              <span
                                style={{
                                  fontFamily: T.mono,
                                  fontSize: 11,
                                  color: T.blue,
                                }}
                              >
                                {e.ticker}
                              </span>
                              <span
                                style={{
                                  fontFamily: T.mono,
                                  fontSize: 9,
                                  color: T.faint,
                                }}
                              >
                                {e.time}
                              </span>
                              {e.note && (
                                <span
                                  style={{
                                    fontSize: 10,
                                    color: T.dim,
                                    lineHeight: 1.3,
                                  }}
                                >
                                  {e.note}
                                </span>
                              )}
                            </div>
                          ))}
                        </div>
                      </div>
                    )}
                  </div>
                </div>
              );
            })}
          </div>
        </div>
      )}
    </div>
  );
}

