// ---------- candlestick chart ----------
const EMPTY_BARS = [];

function aggregateBars(bars, minutes) {
  if (minutes <= 1) {
    return bars.map((b) => ({
      time: Math.floor(new Date(b.ts).getTime() / 1000),
      open: b.o,
      high: b.h,
      low: b.l,
      close: b.c,
    }));
  }
  const out = [];
  let bucket = null;
  let bucketStart = null;
  for (const b of bars) {
    const minuteOfDay = (() => {
      const d = new Date(b.ts);
      return d.getHours() * 60 + d.getMinutes();
    })();
    // bucket boundaries anchored to the 9:30 session open
    const bucketKey = Math.floor((minuteOfDay - 9 * 60 - 30) / minutes);
    if (bucketKey !== bucketStart) {
      if (bucket) out.push(bucket);
      bucketStart = bucketKey;
      bucket = {
        time: Math.floor(new Date(b.ts).getTime() / 1000),
        open: b.o,
        high: b.h,
        low: b.l,
        close: b.c,
      };
    } else {
      bucket.high = Math.max(bucket.high, b.h);
      bucket.low = Math.min(bucket.low, b.l);
      bucket.close = b.c;
    }
  }
  if (bucket) out.push(bucket);
  return out;
}

function CandleChart({ data }) {
  const containerRef = useRef(null);
  const chartRef = useRef(null);
  const seriesRef = useRef(null);

  useEffect(() => {
    const container = containerRef.current;
    const chart = createChart(container, {
      width: container.clientWidth,
      height: 520,
      layout: {
        background: { color: T.panel },
        textColor: T.dim,
        fontFamily: T.mono,
        fontSize: 11,
      },
      grid: {
        vertLines: { color: T.panelEdge },
        horzLines: { color: T.panelEdge },
      },
      localization: {
        timeFormatter: (time) =>
          new Date(time * 1000).toLocaleTimeString("en-US", {
            timeZone: "America/New_York",
            hour: "2-digit",
            minute: "2-digit",
            hour12: false,
          }),
      },
      timeScale: {
        timeVisible: true,
        secondsVisible: false,
        borderColor: T.panelEdge,
        tickMarkFormatter: (time) =>
          new Date(time * 1000).toLocaleTimeString("en-US", {
            timeZone: "America/New_York",
            hour: "2-digit",
            minute: "2-digit",
            hour12: false,
          }),
      },
      rightPriceScale: { borderColor: T.panelEdge },
      crosshair: { mode: 0 },
    });
    const series = chart.addSeries(CandlestickSeries, {
      upColor: T.green,
      downColor: T.red,
      borderVisible: false,
      wickUpColor: T.green,
      wickDownColor: T.red,
    });
    chartRef.current = chart;
    seriesRef.current = series;

    const ro = new ResizeObserver(() => {
      if (containerRef.current) {
        chart.applyOptions({ width: containerRef.current.clientWidth });
      }
    });
    ro.observe(container);

    return () => {
      ro.disconnect();
      chart.remove();
    };
  }, []);

  useEffect(() => {
    if (seriesRef.current) {
      seriesRef.current.setData(data);
      chartRef.current.timeScale().fitContent();
    }
  }, [data]);

  return <div ref={containerRef} style={{ width: "100%" }} />;
}

function DailyCandles({ dayBars, dayIndex, setDayIndex, timeframe, setTimeframe }) {
  const day = dayBars && dayBars.days[dayIndex];
  const bars = (dayBars && dayBars.byDay.get(day)) || EMPTY_BARS;
  const data = useMemo(() => aggregateBars(bars, timeframe), [bars, timeframe]);

  if (!dayBars || dayBars.days.length === 0) return null;
  const navBtn = (disabled) => ({
    ...retryBtn,
    padding: "4px 10px",
    opacity: disabled ? 0.35 : 1,
    cursor: disabled ? "default" : "pointer",
  });

  return (
    <div
      style={{
        background: T.panel,
        border: `1px solid ${T.panelEdge}`,
        borderRadius: 10,
        padding: 14,
        marginBottom: 14,
      }}
    >
      <div
        style={{
          display: "flex",
          flexWrap: "wrap",
          alignItems: "center",
          gap: 10,
          marginBottom: 12,
        }}
      >
        <button
          onClick={() => setDayIndex((i) => Math.max(0, i - 1))}
          disabled={dayIndex === 0}
          style={navBtn(dayIndex === 0)}
        >
          ← Prev
        </button>
        <span style={{ fontFamily: T.mono, fontSize: 12, color: T.ink, minWidth: 90, textAlign: "center" }}>
          {day}
        </span>
        <button
          onClick={() => setDayIndex((i) => Math.min(dayBars.days.length - 1, i + 1))}
          disabled={dayIndex === dayBars.days.length - 1}
          style={navBtn(dayIndex === dayBars.days.length - 1)}
        >
          Next →
        </button>
        <div style={{ display: "flex", gap: 6, marginLeft: "auto" }}>
          {[1, 5, 15].map((m) => {
            const active = m === timeframe;
            return (
              <button
                key={m}
                onClick={() => setTimeframe(m)}
                style={{
                  background: active ? T.amber : "transparent",
                  color: active ? "#141414" : T.dim,
                  border: `1px solid ${active ? T.amber : T.panelEdge}`,
                  borderRadius: 6,
                  padding: "5px 12px",
                  fontFamily: T.mono,
                  fontSize: 11,
                  fontWeight: active ? 700 : 400,
                  cursor: "pointer",
                }}
              >
                {m} min
              </button>
            );
          })}
        </div>
      </div>
      <CandleChart data={data} />
    </div>
  );
}

// ---------- Technicals tab ----------
const TECH_KEY = "smaug-technicals-results";
const TECH_URL_KEY = "smaug-technicals-fetch-url";

const FEATURE_LABELS = {
  rsi14: "RSI (14)",
  ema_spread_bps: "EMA9−EMA21 spread",
  dist_ema9_bps: "Dist. from EMA9",
  dist_ema21_bps: "Dist. from EMA21",
  ret_1m_bps: "1-min return",
  ret_5m_bps: "5-min return",
  range_bps: "Bar range",
  body_ratio: "Body ratio",
  vol_z: "Volume z-score",
  min_since_open: "Minutes since open",
};

const TARGET_LABELS = {
  fwd_5m_bps: "Fwd 5 min",
  fwd_10m_bps: "Fwd 10 min",
  fwd_15m_bps: "Fwd 15 min",
  mfe_10m_bps: "MFE 10 min",
};

const fLabel = (k) => FEATURE_LABELS[k] || k;
const tLabel = (k) => TARGET_LABELS[k] || k;

function HBar({ label, value, maxAbs, format }) {
  const pct = maxAbs > 0 ? (Math.abs(value) / maxAbs) * 100 : 0;
  const color = value >= 0 ? T.green : T.red;
  return (
    <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
      <span
        style={{
          fontSize: 11,
          color: T.dim,
          width: 130,
          flexShrink: 0,
          textAlign: "right",
        }}
      >
        {label}
      </span>
      <div style={{ flex: 1, height: 14, position: "relative" }}>
        <div
          style={{
            position: "absolute",
            left: 0,
            top: 2,
            height: 10,
            width: `${pct}%`,
            minWidth: value !== 0 ? 2 : 0,
            background: color,
            opacity: 0.75,
            borderRadius: 2,
          }}
        />
      </div>
      <span
        style={{
          fontFamily: T.mono,
          fontSize: 11,
          color,
          width: 64,
          flexShrink: 0,
          textAlign: "right",
        }}
      >
        {format(value)}
      </span>
    </div>
  );
}

function DecileChart({ feature, rows }) {
  const maxAbs = Math.max(...rows.map((r) => Math.abs(r.avg_move_bps)), 0.01);
  return (
    <div
      style={{
        background: T.bg,
        border: `1px solid ${T.panelEdge}`,
        borderRadius: 8,
        padding: 12,
      }}
    >
      <div
        style={{
          fontFamily: T.mono,
          fontSize: 10,
          letterSpacing: "0.1em",
          color: T.amber,
          marginBottom: 10,
        }}
      >
        {fLabel(feature).toUpperCase()} · LOW → HIGH DECILES
      </div>
      <div
        style={{
          display: "flex",
          alignItems: "flex-end",
          gap: 4,
          height: 90,
        }}
      >
        {rows.map((r) => {
          const h = (Math.abs(r.avg_move_bps) / maxAbs) * 70;
          const up = r.avg_move_bps >= 0;
          return (
            <div
              key={r.decile}
              title={`D${r.decile}: ${r.avg_move_bps > 0 ? "+" : ""}${r.avg_move_bps} bps (n=${r.n})`}
              style={{
                flex: 1,
                display: "flex",
                flexDirection: "column",
                alignItems: "center",
                justifyContent: "flex-end",
                height: "100%",
              }}
            >
              <div
                style={{
                  width: "100%",
                  height: Math.max(h, 2),
                  background: up ? T.green : T.red,
                  opacity: 0.75,
                  borderRadius: "2px 2px 0 0",
                }}
              />
              <span
                style={{
                  fontFamily: T.mono,
                  fontSize: 8,
                  color: T.faint,
                  marginTop: 3,
                }}
              >
                {r.decile}
              </span>
            </div>
          );
        })}
      </div>
      <div
        style={{
          fontFamily: T.mono,
          fontSize: 9,
          color: T.faint,
          marginTop: 6,
        }}
      >
        bar = avg fwd move (green up / red down)
      </div>
    </div>
  );
}

function validateResults(obj) {
  if (!obj || typeof obj !== "object") return "Not a JSON object.";
  if (!obj.targets || Object.keys(obj.targets).length === 0)
    return "No 'targets' found — is this smaug_results.json?";
  return null;
}

function TechnicalsTab() {
  const [results, setResults] = useState(null);
  const [loadState, setLoadState] = useState("loading");
  const [showPaste, setShowPaste] = useState(false);
  const [pasteText, setPasteText] = useState("");
  const [pasteError, setPasteError] = useState(null);
  const [fetchUrl, setFetchUrl] = useState("");
  const [fetching, setFetching] = useState(false);
  const [target, setTarget] = useState(null);
  const [ai, setAi] = useState({ status: "idle", data: null, error: null });
  const [dayBars, setDayBars] = useState(null); // { days: ["2026-07-10", ...], byDay: Map }
  const [dayIndex, setDayIndex] = useState(0);
  const [timeframe, setTimeframe] = useState(1);

  useEffect(() => {
    (async () => {
      try {
        const resp = await fetch(import.meta.env.BASE_URL + "smaug_bars.json");
        if (!resp.ok) return;
        const parsed = await resp.json();
        const byDay = new Map();
        for (const [ts, o, h, l, c, v] of parsed.bars) {
          const day = ts.slice(0, 10);
          if (!byDay.has(day)) byDay.set(day, []);
          byDay.get(day).push({ ts, o, h, l, c, v });
        }
        const days = [...byDay.keys()].sort();
        setDayBars({ days, byDay });
        setDayIndex(days.length - 1);
      } catch {
        // no candle data available — chart section stays hidden
      }
    })();
  }, []);

  useEffect(() => {
    (async () => {
      try {
        const resp = await fetch(import.meta.env.BASE_URL + "smaug_results.json");
        if (resp.ok) {
          const parsed = await resp.json();
          if (!validateResults(parsed)) {
            setResults(parsed);
            setTarget(Object.keys(parsed.targets)[0]);
            setLoadState("ready");
            return;
          }
        }
      } catch {
        // fall through to stored/manual flows
      }
      try {
        const u = await storage.get(TECH_URL_KEY);
        if (u && u.value) setFetchUrl(u.value);
      } catch {}
      try {
        const r = await storage.get(TECH_KEY);
        if (r) {
          const parsed = JSON.parse(r.value);
          setResults(parsed);
          setTarget(Object.keys(parsed.targets)[0]);
        } else {
          setShowPaste(true);
        }
      } catch {
        setShowPaste(true);
      }
      setLoadState("ready");
    })();
  }, []);

  async function applyResults(parsed) {
    const bad = validateResults(parsed);
    if (bad) {
      setPasteError(bad);
      return false;
    }
    setResults(parsed);
    setTarget(Object.keys(parsed.targets)[0]);
    setShowPaste(false);
    setPasteText("");
    setAi({ status: "idle", data: null, error: null });
    if (storageAvailable) {
      try {
        await storage.set(TECH_KEY, JSON.stringify(parsed));
      } catch {
        // shown next time the paste box opens
      }
    }
    return true;
  }

  async function applyPaste() {
    setPasteError(null);
    let parsed;
    try {
      parsed = JSON.parse(pasteText);
    } catch {
      setPasteError("Couldn't parse that as JSON — copy the full contents of smaug_results.json.");
      return;
    }
    await applyResults(parsed);
  }

  async function fetchFromUrl() {
    setPasteError(null);
    if (!fetchUrl.trim()) {
      setPasteError("Enter your raw GitHub URL first.");
      return;
    }
    setFetching(true);
    try {
      const resp = await fetch(fetchUrl.trim());
      if (!resp.ok) throw new Error(`HTTP ${resp.status}`);
      const parsed = await resp.json();
      const ok = await applyResults(parsed);
      if (ok && storageAvailable) {
        try {
          await storage.set(TECH_URL_KEY, fetchUrl.trim());
        } catch {}
      }
    } catch (err) {
      setPasteError(
        "Auto-fetch failed — this environment may block external requests, " +
        "or the URL is unreachable/private. Paste the JSON below instead."
      );
    }
    setFetching(false);
  }

  async function getAiRead() {
    if (!results || !target) return;
    const t = results.targets[target];
    setAi({ status: "loading", data: null, error: null });
    const payload = {
      target,
      n: t.n,
      date_range: results.date_range,
      correlations: t.correlations,
      r2_train: t.regression.r2_train,
      r2_test: t.regression.r2_test,
      std_coefficients_bps: t.regression.std_coefficients_bps,
      deciles: t.deciles,
    };
    const prompt = `You are a quantitative trading analyst reviewing regression results from SPY 1-minute data. The trader is an intraday options scalper (break-and-retest methodology). Stats for target "${target}" (forward move in basis points):\n\n${JSON.stringify(
      payload
    )}\n\nInterpret honestly. Key context: at 1-min resolution |r| of 0.03-0.05 is meaningful, above 0.10 suggests leakage/bugs; negative test R2 means the fit failed out of sample; monotone decile patterns matter more than coefficients; watch for multicollinearity between EMA-distance features. Respond with ONLY compact JSON, no fences: {"read": ["key finding, under 20 words", "..."], "cautions": ["statistical concern, under 20 words"], "actionable": "one sentence: the single most usable takeaway, or say there isn't one yet"} Max 3 per array. Never invent findings the numbers don't support.`;
    try {
      const data = await askClaude(prompt, { useSearch: false });
      setAi({ status: "done", data, error: null });
    } catch (err) {
      setAi({ status: "error", data: null, error: err.message });
    }
  }

  if (loadState === "loading") {
    return (
      <div style={{ color: T.faint, fontFamily: T.mono, fontSize: 12 }}>
        Loading…
      </div>
    );
  }

  const t = results && target ? results.targets[target] : null;
  const corrs = t ? t.correlations : [];
  const maxCorr = Math.max(...corrs.map(([, v]) => Math.abs(v)), 0.001);
  const coefs = t
    ? Object.entries(t.regression.std_coefficients_bps).sort(
        (a, b) => Math.abs(b[1]) - Math.abs(a[1])
      )
    : [];
  const maxCoef = Math.max(...coefs.map(([, v]) => Math.abs(v)), 0.001);

  return (
    <div>
      {/* source bar */}
      <div
        style={{
          display: "flex",
          flexWrap: "wrap",
          alignItems: "center",
          gap: 14,
          marginBottom: 14,
        }}
      >
        {results ? (
          <span style={{ fontFamily: T.mono, fontSize: 11, color: T.dim }}>
            {results.ticker} · {results.bars_analyzed} bars ·{" "}
            {results.date_range ? results.date_range.join(" → ") : "?"} · run{" "}
            {String(results.generated_at).slice(0, 16).replace("T", " ")}
          </span>
        ) : (
          <span style={{ fontSize: 13, color: T.dim }}>
            No analysis loaded yet.
          </span>
        )}
        <button
          onClick={() => setShowPaste(!showPaste)}
          style={{ ...retryBtn, marginLeft: "auto", padding: "5px 14px" }}
        >
          {showPaste ? "Cancel" : results ? "Update data" : "Paste results"}
        </button>
      </div>

      {/* candlestick chart */}
      <DailyCandles
        dayBars={dayBars}
        dayIndex={dayIndex}
        setDayIndex={setDayIndex}
        timeframe={timeframe}
        setTimeframe={setTimeframe}
      />

      {/* paste box */}
      {showPaste && (
        <div
          style={{
            background: T.panel,
            border: `1px solid ${T.panelEdge}`,
            borderRadius: 10,
            padding: 14,
            marginBottom: 14,
          }}
        >
          <div style={{ fontSize: 13, color: T.dim, marginBottom: 8 }}>
            Auto-fetch from your pipeline repo (raw GitHub URL):
          </div>
          <div style={{ display: "flex", gap: 8, marginBottom: 14 }}>
            <input
              value={fetchUrl}
              onChange={(e) => setFetchUrl(e.target.value)}
              placeholder="https://raw.githubusercontent.com/you/smaug-pipeline/main/smaug_results.json"
              style={{ ...inputStyle, fontFamily: T.mono, fontSize: 11 }}
            />
            <button
              onClick={fetchFromUrl}
              disabled={fetching}
              style={{
                ...retryBtn,
                borderColor: T.amber,
                color: fetching ? T.faint : T.amber,
                padding: "8px 16px",
                fontWeight: 700,
                flexShrink: 0,
              }}
            >
              {fetching ? "Fetching…" : "Fetch"}
            </button>
          </div>
          <div style={{ fontSize: 13, color: T.dim, marginBottom: 8 }}>
            Or paste the full contents of{" "}
            <span style={{ fontFamily: T.mono, color: T.ink }}>
              smaug_results.json
            </span>{" "}
            from your pipeline folder:
          </div>
          <textarea
            value={pasteText}
            onChange={(e) => setPasteText(e.target.value)}
            rows={6}
            placeholder='{"generated_at": ...}'
            style={{
              ...inputStyle,
              fontFamily: T.mono,
              fontSize: 11,
              resize: "vertical",
            }}
          />
          {pasteError && (
            <div style={{ fontSize: 12, color: T.red, marginTop: 8 }}>
              {pasteError}
            </div>
          )}
          <button
            onClick={applyPaste}
            style={{
              background: T.amber,
              color: "#141414",
              border: "none",
              borderRadius: 8,
              padding: "9px 18px",
              fontSize: 13,
              fontWeight: 700,
              cursor: "pointer",
              fontFamily: T.sans,
              marginTop: 10,
            }}
          >
            Load analysis
          </button>
        </div>
      )}

      {t && (
        <>
          {/* target selector */}
          <div
            style={{
              display: "flex",
              flexWrap: "wrap",
              gap: 6,
              marginBottom: 14,
            }}
          >
            {Object.keys(results.targets).map((k) => {
              const active = k === target;
              return (
                <button
                  key={k}
                  onClick={() => {
                    setTarget(k);
                    setAi({ status: "idle", data: null, error: null });
                  }}
                  style={{
                    background: active ? T.amber : "transparent",
                    color: active ? "#141414" : T.dim,
                    border: `1px solid ${active ? T.amber : T.panelEdge}`,
                    borderRadius: 6,
                    padding: "5px 12px",
                    fontFamily: T.mono,
                    fontSize: 11,
                    fontWeight: active ? 700 : 400,
                    cursor: "pointer",
                  }}
                >
                  {tLabel(k)}
                </button>
              );
            })}
            <button
              onClick={getAiRead}
              disabled={ai.status === "loading"}
              style={{
                ...retryBtn,
                marginLeft: "auto",
                borderColor: T.amber,
                color: ai.status === "loading" ? T.faint : T.amber,
                padding: "5px 14px",
                fontWeight: 700,
              }}
            >
              {ai.status === "loading" ? "Analyzing…" : "AI read"}
            </button>
          </div>

          {/* AI read panel */}
          {ai.status === "error" && (
            <div style={{ fontSize: 12, color: T.red, marginBottom: 12 }}>
              {ai.error}{" "}
              <button onClick={getAiRead} style={{ ...retryBtn, marginLeft: 6 }}>
                Retry
              </button>
            </div>
          )}
          {ai.status === "done" && ai.data && (
            <div
              style={{
                background: T.panel,
                border: `1px solid ${T.amber}`,
                borderRadius: 10,
                padding: 14,
                marginBottom: 14,
              }}
            >
              <div
                style={{
                  display: "grid",
                  gridTemplateColumns: "repeat(auto-fit, minmax(220px, 1fr))",
                  gap: 14,
                  marginBottom: ai.data.actionable ? 12 : 0,
                }}
              >
                {[
                  ["READ", ai.data.read, T.ink],
                  ["CAUTIONS", ai.data.cautions, T.red],
                ].map(
                  ([label, items, color]) =>
                    items &&
                    items.length > 0 && (
                      <div key={label}>
                        <div
                          style={{
                            fontFamily: T.mono,
                            fontSize: 10,
                            letterSpacing: "0.12em",
                            color,
                            marginBottom: 6,
                          }}
                        >
                          {label}
                        </div>
                        {items.map((item, i) => (
                          <div
                            key={i}
                            style={{ display: "flex", gap: 7, marginBottom: 5 }}
                          >
                            <span style={{ color, flexShrink: 0 }}>▸</span>
                            <span
                              style={{
                                fontSize: 12,
                                color: T.dim,
                                lineHeight: 1.4,
                              }}
                            >
                              {item}
                            </span>
                          </div>
                        ))}
                      </div>
                    )
                )}
              </div>
              {ai.data.actionable && (
                <div
                  style={{
                    paddingTop: 10,
                    borderTop: `1px solid ${T.panelEdge}`,
                    fontSize: 13,
                  }}
                >
                  <span
                    style={{
                      fontFamily: T.mono,
                      fontSize: 10,
                      letterSpacing: "0.12em",
                      color: T.amber,
                    }}
                  >
                    TAKEAWAY ·{" "}
                  </span>
                  <span style={{ color: T.ink }}>{ai.data.actionable}</span>
                </div>
              )}
            </div>
          )}

          {/* stats grid */}
          <div
            style={{
              display: "grid",
              gridTemplateColumns: "repeat(auto-fit, minmax(300px, 1fr))",
              gap: 14,
              marginBottom: 14,
            }}
          >
            {/* correlations */}
            <div
              style={{
                background: T.panel,
                border: `1px solid ${T.panelEdge}`,
                borderRadius: 10,
                padding: 14,
              }}
            >
              <div
                style={{
                  fontFamily: T.mono,
                  fontSize: 10,
                  letterSpacing: "0.12em",
                  color: T.amber,
                  marginBottom: 10,
                }}
              >
                CORRELATION WITH {tLabel(target).toUpperCase()} · n={t.n}
              </div>
              <div
                style={{ display: "flex", flexDirection: "column", gap: 5 }}
              >
                {corrs.map(([f, v]) => (
                  <HBar
                    key={f}
                    label={fLabel(f)}
                    value={v}
                    maxAbs={maxCorr}
                    format={(x) => (x > 0 ? "+" : "") + x.toFixed(4)}
                  />
                ))}
              </div>
            </div>

            {/* regression */}
            <div
              style={{
                background: T.panel,
                border: `1px solid ${T.panelEdge}`,
                borderRadius: 10,
                padding: 14,
              }}
            >
              <div
                style={{
                  fontFamily: T.mono,
                  fontSize: 10,
                  letterSpacing: "0.12em",
                  color: T.amber,
                  marginBottom: 10,
                }}
              >
                REGRESSION · BPS PER 1σ OF FEATURE
              </div>
              <div
                style={{
                  display: "flex",
                  gap: 20,
                  marginBottom: 12,
                  fontFamily: T.mono,
                  fontSize: 12,
                }}
              >
                <span style={{ color: T.dim }}>
                  R² train{" "}
                  <span style={{ color: T.ink }}>
                    {t.regression.r2_train.toFixed(4)}
                  </span>
                </span>
                <span style={{ color: T.dim }}>
                  R² test{" "}
                  <span
                    style={{
                      color: t.regression.r2_test > 0 ? T.green : T.red,
                      fontWeight: 700,
                    }}
                  >
                    {t.regression.r2_test.toFixed(4)}
                  </span>
                </span>
              </div>
              {t.regression.r2_test <= 0 && (
                <div
                  style={{
                    fontSize: 11,
                    color: T.red,
                    marginBottom: 10,
                    lineHeight: 1.4,
                  }}
                >
                  Negative test R² — the fitted model did not generalize.
                  Treat coefficients as descriptive, not predictive.
                </div>
              )}
              <div
                style={{ display: "flex", flexDirection: "column", gap: 5 }}
              >
                {coefs.map(([f, v]) => (
                  <HBar
                    key={f}
                    label={fLabel(f)}
                    value={v}
                    maxAbs={maxCoef}
                    format={(x) => (x > 0 ? "+" : "") + x.toFixed(2)}
                  />
                ))}
              </div>
            </div>
          </div>

          {/* deciles */}
          <div
            style={{
              display: "grid",
              gridTemplateColumns: "repeat(auto-fit, minmax(260px, 1fr))",
              gap: 14,
            }}
          >
            {Object.entries(t.deciles || {}).map(([f, rows]) => (
              <DecileChart key={f} feature={f} rows={rows} />
            ))}
          </div>
        </>
      )}
    </div>
  );
}

