function ApiKeySettings() {
  const [open, setOpen] = useState(false);
  const [key, setKey] = useState(() => localStorage.getItem(API_KEY_STORAGE_KEY) || "");
  const [savedFlash, setSavedFlash] = useState(false);

  function save() {
    localStorage.setItem(API_KEY_STORAGE_KEY, key.trim());
    setSavedFlash(true);
    setTimeout(() => setSavedFlash(false), 1500);
  }
  function clear() {
    localStorage.removeItem(API_KEY_STORAGE_KEY);
    setKey("");
  }

  const btnStyle = {
    background: T.panel,
    border: `1px solid ${T.panelEdge}`,
    borderRadius: 6,
    color: T.ink,
    fontSize: 12,
    padding: "5px 10px",
    cursor: "pointer",
  };

  return (
    <div style={{ position: "relative" }}>
      <button
        onClick={() => setOpen((o) => !o)}
        aria-label="Settings"
        title="Anthropic API key settings"
        style={{
          background: "transparent",
          border: `1px solid ${T.panelEdge}`,
          borderRadius: 6,
          color: T.dim,
          width: 32,
          height: 32,
          cursor: "pointer",
          fontSize: 16,
          lineHeight: "30px",
        }}
      >
        ⚙
      </button>
      {open && (
        <div
          style={{
            position: "absolute",
            top: 40,
            right: 0,
            background: T.panel,
            border: `1px solid ${T.panelEdge}`,
            borderRadius: 8,
            padding: 14,
            width: 260,
            zIndex: 20,
            boxShadow: "0 8px 24px rgba(0,0,0,0.4)",
          }}
        >
          <div style={{ fontSize: 12, color: T.dim, marginBottom: 8 }}>
            Anthropic API key (stored only in this browser)
          </div>
          <input
            type="password"
            value={key}
            onChange={(e) => setKey(e.target.value)}
            placeholder="sk-ant-..."
            style={{
              width: "100%",
              boxSizing: "border-box",
              background: T.bg,
              border: `1px solid ${T.panelEdge}`,
              borderRadius: 6,
              color: T.ink,
              padding: "6px 8px",
              fontSize: 13,
              marginBottom: 8,
            }}
          />
          <div style={{ display: "flex", gap: 8 }}>
            <button onClick={save} style={{ ...btnStyle, borderColor: T.amber, color: T.amber }}>
              Save
            </button>
            <button onClick={clear} style={btnStyle}>
              Clear
            </button>
          </div>
          {savedFlash && (
            <div style={{ color: T.green, fontSize: 11, marginTop: 6 }}>Saved.</div>
          )}
        </div>
      )}
    </div>
  );
}

// ---------- Raw Data tab ----------
function RawDataTab() {
  const [dayBars, setDayBars] = useState(null);
  const [dayIndex, setDayIndex] = useState(0);
  const [loadState, setLoadState] = useState("loading");

  useEffect(() => {
    (async () => {
      try {
        const resp = await fetch(import.meta.env.BASE_URL + "smaug_bars.json");
        if (resp.ok) {
          const parsed = await resp.json();
          const byDay = new Map();
          for (const [ts, o, h, l, c, v] of parsed.bars) {
            const day = ts.slice(0, 10);
            if (!byDay.has(day)) byDay.set(day, []);
            byDay.get(day).push({ ts, o, h, l, c, v });
          }
          const days = [...byDay.keys()].sort();
          setDayBars({ days, byDay });
          setDayIndex(days.length - 1);
        }
      } catch {
        // no bar data available
      }
      setLoadState("ready");
    })();
  }, []);

  if (loadState === "loading") {
    return (
      <div style={{ color: T.faint, fontFamily: T.mono, fontSize: 12 }}>
        Loading…
      </div>
    );
  }

  if (!dayBars || dayBars.days.length === 0) {
    return (
      <div style={{ color: T.dim, fontSize: 13 }}>
        No bar data found. Run the pipeline to generate smaug_bars.json.
      </div>
    );
  }

  const day = dayBars.days[dayIndex];
  const bars = dayBars.byDay.get(day) || [];
  const navBtn = (disabled) => ({
    ...retryBtn,
    padding: "4px 10px",
    opacity: disabled ? 0.35 : 1,
    cursor: disabled ? "default" : "pointer",
  });
  const fmtTime = (ts) =>
    new Date(ts).toLocaleTimeString("en-US", {
      timeZone: "America/New_York",
      hour: "2-digit",
      minute: "2-digit",
      hour12: false,
    });
  const th = {
    position: "sticky",
    top: 0,
    background: T.panel,
    color: T.dim,
    fontFamily: T.mono,
    fontSize: 11,
    fontWeight: 400,
    textAlign: "right",
    padding: "6px 12px",
    borderBottom: `1px solid ${T.panelEdge}`,
  };
  const td = {
    fontFamily: T.mono,
    fontSize: 12,
    color: T.ink,
    textAlign: "right",
    padding: "4px 12px",
    borderBottom: `1px solid ${T.panelEdge}`,
  };

  return (
    <div>
      <div
        style={{
          display: "flex",
          flexWrap: "wrap",
          alignItems: "center",
          gap: 10,
          marginBottom: 14,
        }}
      >
        <button
          onClick={() => setDayIndex((i) => Math.max(0, i - 1))}
          disabled={dayIndex === 0}
          style={navBtn(dayIndex === 0)}
        >
          ← Prev
        </button>
        <span
          style={{
            fontFamily: T.mono,
            fontSize: 12,
            color: T.ink,
            minWidth: 90,
            textAlign: "center",
          }}
        >
          {day}
        </span>
        <button
          onClick={() => setDayIndex((i) => Math.min(dayBars.days.length - 1, i + 1))}
          disabled={dayIndex === dayBars.days.length - 1}
          style={navBtn(dayIndex === dayBars.days.length - 1)}
        >
          Next →
        </button>
        <span style={{ fontFamily: T.mono, fontSize: 11, color: T.faint, marginLeft: "auto" }}>
          {bars.length} bars
        </span>
      </div>

      <div
        style={{
          background: T.panel,
          border: `1px solid ${T.panelEdge}`,
          borderRadius: 10,
          maxHeight: 560,
          overflowY: "auto",
        }}
      >
        <table style={{ width: "100%", borderCollapse: "collapse" }}>
          <thead>
            <tr>
              <th style={{ ...th, textAlign: "left" }}>Time (ET)</th>
              <th style={th}>Open</th>
              <th style={th}>High</th>
              <th style={th}>Low</th>
              <th style={th}>Close</th>
              <th style={th}>Volume</th>
            </tr>
          </thead>
          <tbody>
            {bars.map((b) => (
              <tr key={b.ts}>
                <td style={{ ...td, textAlign: "left", color: T.dim }}>{fmtTime(b.ts)}</td>
                <td style={td}>{b.o.toFixed(2)}</td>
                <td style={td}>{b.h.toFixed(2)}</td>
                <td style={td}>{b.l.toFixed(2)}</td>
                <td style={{ ...td, color: b.c >= b.o ? T.green : T.red }}>{b.c.toFixed(2)}</td>
                <td style={td}>{b.v.toLocaleString()}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}

// ---------- main ----------
const TABS = ["Morning Brief", "Journal", "Modeling", "Raw Data", "Resources"];

export default function Smaug() {
  const now = useEtClock();
  const countdown = openCountdown(now);
  const [tab, setTab] = useState("Morning Brief");
  const [panels, setPanels] = useState({
    econ: { status: "idle", data: null, error: null },
    earnings: { status: "idle", data: null, error: null },
    sentiment: { status: "idle", data: null, error: null },
    cases: { status: "idle", data: null, error: null },
  });
  const [lastRun, setLastRun] = useState(null);

  const anyLoading = Object.values(panels).some((p) => p.status === "loading");

  function setPanel(key, patch) {
    setPanels((prev) => ({ ...prev, [key]: { ...prev[key], ...patch } }));
  }

  async function runPanel(key) {
    const prompts = buildPrompts();
    setPanel(key, { status: "loading", error: null });
    try {
      const data = await askClaude(prompts[key]);
      setPanel(key, { status: "done", data });
    } catch (err) {
      setPanel(key, { status: "error", error: err.message });
    }
  }

  async function runAll() {
    setLastRun(etNow());
    const keys = ["econ", "earnings", "sentiment", "cases"];
    keys.forEach((k) => setPanel(k, { status: "loading", error: null }));
    for (const key of keys) {
      await runPanel(key);
    }
  }

  return (
    <div
      style={{
        minHeight: "100vh",
        background: T.bg,
        fontFamily: T.sans,
        color: T.ink,
        padding: "20px 18px 40px",
      }}
    >
      <style>{`
        @keyframes pulse { 0%,100%{opacity:.25} 50%{opacity:1} }
        button:focus-visible, a:focus-visible { outline: 2px solid ${T.amber}; outline-offset: 2px; }
        input:focus, select:focus { border-color: ${T.amber} !important; }
        @media (prefers-reduced-motion: reduce) { * { animation: none !important; } }
      `}</style>

      <div style={{ maxWidth: 1100, margin: "0 auto" }}>
        {/* header: left stack (wordmark, date, session, tabs) + logo right */}
        <div
          style={{
            display: "flex",
            flexWrap: "wrap",
            alignItems: "center",
            justifyContent: "space-between",
            gap: 14,
            marginBottom: 14,
          }}
        >
          <div style={{ minWidth: 0 }}>
            <img
              src={WORDMARK}
              alt="SMAUG"
              style={{
                display: "block",
                height: 40,
                width: "auto",
                maxWidth: "100%",
              }}
            />
            <div
              style={{
                width: 120,
                height: 2,
                background: T.amber,
                margin: "8px 0 6px",
              }}
            />
            <div
              style={{
                fontSize: 13,
                color: T.dim,
                fontWeight: 300,
                marginBottom: 10,
              }}
            >
              {todayLabel()}
            </div>

            {/* session strip */}
            <div
              style={{
                display: "inline-flex",
                flexWrap: "wrap",
                alignItems: "center",
                gap: 18,
                fontFamily: T.mono,
                fontSize: 12,
                color: T.dim,
                borderTop: `1px solid ${T.panelEdge}`,
                borderBottom: `1px solid ${T.panelEdge}`,
                padding: "8px 24px 8px 2px",
                marginBottom: 10,
              }}
            >
              <span>
                ET{" "}
                <span style={{ color: T.ink }}>
                  {now.toLocaleTimeString("en-US", { hour12: false })}
                </span>
              </span>
              <span style={{ color: countdown.tone }}>{countdown.label}</span>
            </div>

            {/* tabs */}
            <div
              style={{
                display: "flex",
                gap: 4,
                overflowX: "auto",
              }}
            >
          {TABS.map((t) => {
            const active = tab === t;
            return (
              <button
                key={t}
                onClick={() => setTab(t)}
                style={{
                  background: "transparent",
                  border: "none",
                  borderBottom: active
                    ? `2px solid ${T.amber}`
                    : "2px solid transparent",
                  color: active ? T.ink : T.faint,
                  fontFamily: T.display,
                  fontSize: 18,
                  letterSpacing: "0.06em",
                  padding: "6px 14px",
                  cursor: "pointer",
                  whiteSpace: "nowrap",
                }}
              >
                {t.toUpperCase()}
              </button>
            );
          })}
            </div>
          </div>

          <div
            style={{
              display: "flex",
              flexDirection: "column",
              alignItems: "flex-end",
              gap: 8,
              flexShrink: 0,
            }}
          >
            <ApiKeySettings />
            <img
              src={LOGO}
              alt="Smaug logo"
              width={180}
              height={180}
              style={{ display: "block", flexShrink: 0 }}
            />
          </div>
        </div>

        {/* tab content */}
        {tab === "Morning Brief" && (
          <MorningBriefTab
            panels={panels}
            runPanel={runPanel}
            runAll={runAll}
            anyLoading={anyLoading}
            lastRun={lastRun}
          />
        )}
        {tab === "Journal" && <JournalTab />}
        {tab === "Modeling" && <TechnicalsTab />}
        {tab === "Raw Data" && <RawDataTab />}
        {tab === "Resources" && <ResourcesTab />}
      </div>
    </div>
  );
}
